SELECT
    a.alarm_id,
    a.alarm_beginTime,
    a.alarm_endTime,
    a.alarm_type,
    a.alarm_rank,
    s.sequence_name,
    c.row_index,
    c.groove_number,
    s.first_electrodes_polarity,
    c.observation_place,
    c.subdivide_number
FROM
    alarm_electrolytic_cell c
        LEFT JOIN alarm a ON a.alarm_id = c.alarm_id
        LEFT JOIN electrolytic_cell_sequence s ON s.sequence_id = c.sequence_id

    1=1
     and c.alarm_id = #{alarmId}
     and c.sequence_id = #{sequenceId}
     and c.row_index = #{rowIndex}
     and c.groove_number = #{grooveNumber}
     and c.subdivide_number = #{busBarsNumber} and c.observation_place =2
     and c.subdivide_number = #{electrodesNumber} and c.observation_place =1
     and c.observation_place = #{observationPlace}
     and c.temperature_variation >= #{temperatureVariation}

     and a.alarm_type = #{alarmType}
     and a.alarm_rank = #{alarmRank}
     and a.alarm_beginTime >= #{startDate}
     and a.alarm_beginTime <= #{endDate}
    and a.device_id = #{deviceId}
    and a.del_flag = '0'

ORDER BY
    a.alarm_beginTime DESC

